// public-facing worker

addEventListener('fetch', async (event) => {
  const url = new URL(event.request.url);
  const workerName = url.pathname.substring(1);

  const serviceBinding = await getServiceBinding(workerName);
  const worker = await importScripts(serviceBinding.endpoint);

  const response = await worker.default(event.request);
  event.respondWith(response);
});

async function getServiceBinding(name) {
  const serviceBindings = await getGlobalKV('serviceBindings');
  return serviceBindings.get(name);
}

